func initializeCRUDServiceRegistry(mdr *svcfw.MDRegistry, isExternal bool) {
	var (
		csr       *svcfw.CRUDServiceRegistry
		customCSR *svcfw.CustomServiceRegistry
	)
	_, _ = csr, customCSR
	csr = mdr.PubCRUDServiceRegistry
	func() {
		// set swagger jsons for our and external schemas
		csr.CRUDSwaggerRegistry["ves.io.schema.views.bigip_http_proxy.Object"] = APISwaggerJSON
		csr.CRUDGrpcClientRegistry["ves.io.schema.views.bigip_http_proxy.Object"] = NewCRUDAPIGrpcClient
		csr.CRUDRestClientRegistry["ves.io.schema.views.bigip_http_proxy.Object"] = NewCRUDAPIRestClient
		csr.CRUDInprocClientRegistry["ves.io.schema.views.bigip_http_proxy.Object"] = NewCRUDAPIInprocClient
		if isExternal {
			return
		}
		// registration of api handlers if our own schema
		mdr.SvcRegisterHandlers["ves.io.schema.views.bigip_http_proxy.API"] = RegisterAPIServer
		mdr.SvcGwRegisterHandlers["ves.io.schema.views.bigip_http_proxy.API"] = RegisterGwAPIHandler
		csr.CRUDServerRegistry["ves.io.schema.views.bigip_http_proxy.Object"] = NewCRUDAPIServer
	}()
}

func InitializeMDRegistry(mdr *svcfw.MDRegistry, isExternal bool) {
	initializeEntryRegistry(mdr)
	initializeValidatorRegistry(mdr.ValidatorRegistry)
	initializeCRUDServiceRegistry(mdr, isExternal)
	initializeRPCRegistry(mdr)
	if isExternal {
		return
	}
	initializeAPIGwServiceSlugsRegistry(mdr.APIGwServiceSlugs)
	initializeP0PolicyRegistry(mdr.P0PolicyRegistry)
}
